mapper.update:
/* 요금적용전력 수정 */ UPDATE tb_charge_power
site_id = #{entity.siteId},
std_date = #{entity.stdDate},
charge_power = #{entity.chargePower},
reg_date = #{entity.regDate},
WHERE chg_pwr_idx = #{entity.chgPwrIdx}

mapper.delete:
/* 요금적용전력 삭제 */
DELETE FROM tb_charge_power 
 WHERE chg_pwr_idx = #{chgPwrIdx}

mapper.select:
/* 요금적용전력 전체 개수 조회 */
SELECT COUNT(*) AS CNT
  FROM tb_charge_power
 WHERE chg_pwr_idx = #{chgPwrIdx}
